def decode_jwt(token, secret, algorithms=['HS256']):
    try:
        decoded = jwt.decode(token, secret, algorithms=algorithms, options={"verify_exp": False})
        return decoded
    except jwt.ExpiredSignatureError:
        return "Token has expired"
